module median_filter (
    input [2:0] pixel0, pixel1, pixel2,
    input [2:0] pixel3, pixel4, pixel5,
    input [2:0] pixel6, pixel7, pixel8,
    output reg [2:0] median
);

reg [2:0] obf_sorted [0:8];

integer i, j;

always @(*) begin
    // Store the pixels in an array
    obf_sorted[0] = pixel0;
    obf_sorted[1] = pixel1;
    obf_sorted[2] = pixel2;
    obf_sorted[3] = pixel3;
    obf_sorted[4] = pixel4;
    obf_sorted[5] = pixel5;
    obf_sorted[6] = pixel6;
    obf_sorted[7] = pixel7;
    obf_sorted[8] = pixel8;

    // Sort the array using bubble sort
    for (i = 0; i < 9; i = i + 1) begin
        for (j = 0; j < 8 - i; j = j + 1) begin
            if (obf_sorted[j] > obf_sorted[j + 1]) begin
                // Swap
                {obf_sorted[j], obf_sorted[j + 1]} = {obf_sorted[j + 1], obf_sorted[j]};
            end
        end
    end

    // The median is the 5th element in the obf_sorted list
    median = obf_sorted[4];
end

endmodule
